 */
class NexusPersona(projectRoot: String? = null) : BaseActivePersona(projectRoot) {
    init {
        this.name = "Nexus"
        this.emoji = "🌐"
        this.role = "PhD Network Resilience Engineer"
        this.phd_identity = "Robust Networking & HTTP Resiliency (TypeScript)"
        this.stack = "Kotlin"
        this.healingPrompt = ""
