        return mapOf(
            "extensions" to listOf([".kt"]),
            "rules" to listOf<AuditRule>(
                // [
          {
                    "regex": "fetch\\s*\\([^)]*\\)(?![\\s\\S]{0,100}signal|timeout|AbortController)",
                    "issue": "Fragilidade: fetch() sem timeout ou AbortController — pendurado para sempre PhD.",
                    "severity": "high"
          },
          {
                    "regex": "axios\\.(?:get|post)\\([^)]*\\)(?![\\s\\S]{0,50}timeout)",
                    "issue": "Fragilidade: Chamada axios sem timeout configurado PhD.",
                    "severity": "high"
          },
          {
                    "regex": "setTimeout\\s*\\([^)]*,\\s*0\\s*\\)",
                    "issue": "Hack: setTimeout(fn, 0) — geralmente indica problema de design estrutural PhD.",
                    "severity": "low"
          },
          {
                    "regex": "WebSocket\\s*\\([^)]*\\)(?![\\s\\S]{0,100}onclose|onerror)",
                    "issue": "Conexão Frágil: WebSocket sem handler de erro ou desconexão PhD.",
                    "severity": "high"
          }
]
            )
        )
    }

    fun performAudit() {
        println("☕ [${name}] Starting fleet-wide audit via Hub PhD...")
